const items = $input.all();
const root = items[0].json;

if (!root.data || !Array.isArray(root.data)) {
  throw new Error('Expected root.data to be an array from this UEX endpoint');
}

return root.data.map(row => {

  let asset_type;
  let asset_source_id;

  // Detect type based on which ID exists
  if (row.id_item !== undefined) {
    // Item pricing
    asset_type = 'item';
    asset_source_id = `items:${row.id_item}`;
  } else if (row.id_commodity !== undefined) {
    // Commodity pricing
    asset_type = 'commodity';
    asset_source_id = `commodities:${row.id_commodity}`;
  } else {
    throw new Error('Row does not contain id_item or id_commodity — cannot determine asset type');
  }

  return {
    json: {
      row,
      asset_type,
      asset_source_id
    }
  };
});
